// 3D Earth Map Component - Dũng
import React, { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
import './EarthMap.css';

const PHASE_ROTATING  = 'rotating';
const PHASE_ZOOMING   = 'zooming';
const PHASE_STOPPED   = 'stopped';

const ROTATE_DURATION = 1.0;  // seconds of fast spin
const ZOOM_DURATION   = 2.0;  // seconds of smooth zoom

// Target camera position to view Palmer Archipelago (southern hemisphere)
const TARGET_CAM = new THREE.Vector3(0, -1.2, 2.6);
const START_CAM  = new THREE.Vector3(0, 0, 5);

const islands = [
  { name: 'Biscoe',    lat: -64.85, lon: -63.59, description: 'Adélie Penguins – Largest population',  population: '15,000+' },
  { name: 'Dream',     lat: -64.73, lon: -64.25, description: 'Chinstrap Penguins – Distinctive stripe', population: '8,000+' },
  { name: 'Torgersen', lat: -64.77, lon: -64.05, description: 'Gentoo Penguins – Fast swimmers',         population: '5,000+' },
];

const latLonToVector3 = (lat, lon, radius) => {
  const phi   = (90 - lat) * (Math.PI / 180);
  const theta = (lon + 180) * (Math.PI / 180);
  return new THREE.Vector3(
    -(radius * Math.sin(phi) * Math.cos(theta)),
     (radius * Math.cos(phi)),
     (radius * Math.sin(phi) * Math.sin(theta))
  );
};

const easeInOutCubic = (t) =>
  t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

const createEarthTexture = () => {
  const canvas = document.createElement('canvas');
  canvas.width  = 2048;
  canvas.height = 1024;
  const ctx = canvas.getContext('2d');

  const oceanGradient = ctx.createLinearGradient(0, 0, 0, 1024);
  oceanGradient.addColorStop(0,   '#1565c0');
  oceanGradient.addColorStop(0.5, '#0d47a1');
  oceanGradient.addColorStop(1,   '#062e5a');
  ctx.fillStyle = oceanGradient;
  ctx.fillRect(0, 0, 2048, 1024);

  const continents = [
    { x: 380,  y: 270,  w: 420, h: 310 }, // North America
    { x: 540,  y: 580,  w: 210, h: 320 }, // South America
    { x: 980,  y: 220,  w: 260, h: 210 }, // Europe
    { x: 1040, y: 480,  w: 260, h: 380 }, // Africa
    { x: 1280, y: 270,  w: 520, h: 360 }, // Asia
    { x: 1620, y: 680,  w: 210, h: 160 }, // Australia
    { x: 1024, y: 930,  w: 1800, h: 140 }, // Antarctica
  ];

  continents.forEach(c => {
    const g = ctx.createRadialGradient(
      c.x + c.w / 2, c.y + c.h / 2, 0,
      c.x + c.w / 2, c.y + c.h / 2, Math.max(c.w, c.h)
    );
    g.addColorStop(0,   '#4caf50');
    g.addColorStop(0.5, '#2d6a4f');
    g.addColorStop(1,   '#1a4036');
    ctx.beginPath();
    ctx.ellipse(c.x + c.w / 2, c.y + c.h / 2, c.w / 2, c.h / 2, 0, 0, Math.PI * 2);
    ctx.fillStyle = g;
    ctx.fill();
  });

  for (let i = 0; i < 4000; i++) {
    ctx.fillStyle = `rgba(255,255,255,${Math.random() * 0.08})`;
    ctx.fillRect(Math.random() * 2048, Math.random() * 1024, 2, 2);
  }

  return new THREE.CanvasTexture(canvas);
};

const EarthMap = () => {
  const containerRef = useRef(null);
  const phaseRef     = useRef(PHASE_ROTATING);
  const phaseTimeRef = useRef(0);   // time spent in current phase (seconds)
  const earthRef     = useRef(null);
  const cameraRef    = useRef(null);
  const clockRef     = useRef(new THREE.Clock());
  const [isLoaded, setIsLoaded]     = useState(false);
  const [hoveredIsland, setHoveredIsland] = useState(null);

  // Raycaster for hover
  const raycasterRef  = useRef(new THREE.Raycaster());
  const mouseRef      = useRef(new THREE.Vector2(-9999, -9999));
  const markersRef    = useRef([]);
  const rendererRef   = useRef(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // ── Scene ──────────────────────────────────────────────────────────────
    const scene = new THREE.Scene();

    // ── Camera ─────────────────────────────────────────────────────────────
    const camera = new THREE.PerspectiveCamera(
      45, container.clientWidth / container.clientHeight, 0.1, 1000
    );
    camera.position.copy(START_CAM);
    camera.lookAt(0, 0, 0);
    cameraRef.current = camera;

    // ── Renderer ───────────────────────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(container.clientWidth, container.clientHeight);
    renderer.setPixelRatio(window.devicePixelRatio);
    container.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // ── Lights ─────────────────────────────────────────────────────────────
    scene.add(new THREE.AmbientLight(0x404040, 0.6));
    const sun = new THREE.DirectionalLight(0xffffff, 1.5);
    sun.position.set(5, 3, 5);
    scene.add(sun);

    // ── Earth ──────────────────────────────────────────────────────────────
    const earthGeo = new THREE.SphereGeometry(1.5, 64, 64);
    const earthTex = createEarthTexture();
    const earthMat = new THREE.MeshPhongMaterial({
      map: earthTex, bumpMap: earthTex, bumpScale: 0.04,
      specular: new THREE.Color(0x222222), shininess: 5,
    });
    const earth = new THREE.Mesh(earthGeo, earthMat);
    scene.add(earth);
    earthRef.current = earth;

    // ── Atmosphere ─────────────────────────────────────────────────────────
    const atmoGeo = new THREE.SphereGeometry(1.6, 64, 64);
    const atmoMat = new THREE.ShaderMaterial({
      vertexShader: `
        varying vec3 vNormal;
        void main() {
          vNormal = normalize(normalMatrix * normal);
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
        }`,
      fragmentShader: `
        varying vec3 vNormal;
        void main() {
          float i = pow(0.7 - dot(vNormal, vec3(0,0,1.0)), 2.0);
          gl_FragColor = vec4(0.3, 0.6, 1.0, 1.0) * i;
        }`,
      blending: THREE.AdditiveBlending,
      side: THREE.BackSide,
      transparent: true,
    });
    scene.add(new THREE.Mesh(atmoGeo, atmoMat));

    // ── Stars ──────────────────────────────────────────────────────────────
    const starVerts = [];
    for (let i = 0; i < 10000; i++) {
      starVerts.push(
        (Math.random() - 0.5) * 2000,
        (Math.random() - 0.5) * 2000,
        (Math.random() - 0.5) * 2000
      );
    }
    const starGeo = new THREE.BufferGeometry();
    starGeo.setAttribute('position', new THREE.Float32BufferAttribute(starVerts, 3));
    scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({ color: 0xffffff, size: 0.02 })));

    // ── Island markers ─────────────────────────────────────────────────────
    markersRef.current = [];
    islands.forEach(island => {
      const pos = latLonToVector3(island.lat, island.lon, 1.53);

      const marker = new THREE.Mesh(
        new THREE.SphereGeometry(0.045, 32, 32),
        new THREE.MeshBasicMaterial({ color: 0xFFD43B })
      );
      marker.position.copy(pos);
      marker.userData = island;
      scene.add(marker);
      markersRef.current.push(marker);

      const glow = new THREE.Mesh(
        new THREE.SphereGeometry(0.1, 32, 32),
        new THREE.MeshBasicMaterial({ color: 0xFFD43B, transparent: true, opacity: 0.25 })
      );
      glow.position.copy(pos);
      scene.add(glow);
    });

    // ── Controls (disabled – we drive camera manually) ──────────────────────
    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableZoom   = false;
    controls.enablePan    = false;
    controls.enableRotate = false;

    setIsLoaded(true);
    clockRef.current.start();
    phaseRef.current    = PHASE_ROTATING;
    phaseTimeRef.current = 0;

    // ── Animation loop ─────────────────────────────────────────────────────
    let animFrameId;
    const animate = () => {
      animFrameId = requestAnimationFrame(animate);
      const delta = clockRef.current.getDelta();

      const phase = phaseRef.current;

      if (phase === PHASE_ROTATING) {
        // Spin at 1.3 rev/s  →  1.3 * 2π rad/s
        earth.rotation.y += 0.8 * Math.PI * 2 * delta;
        phaseTimeRef.current += delta;

        if (phaseTimeRef.current >= ROTATE_DURATION) {
          phaseRef.current     = PHASE_ZOOMING;
          phaseTimeRef.current = 0;
        }

      } else if (phase === PHASE_ZOOMING) {
        phaseTimeRef.current += delta;
        const t = Math.min(phaseTimeRef.current / ZOOM_DURATION, 1);
        const e = easeInOutCubic(t);

        // Smoothly move camera from START_CAM to TARGET_CAM
        camera.position.lerpVectors(START_CAM, TARGET_CAM, e);
        camera.lookAt(0, -0.5, 0);

