          phaseTimeRef.current = 0;
          camera.position.copy(TARGET_CAM);
          camera.lookAt(0, -0.5, 0);
        }

      } else {
        // STOPPED – nothing moves
      }

      // Hover raycasting
      raycasterRef.current.setFromCamera(mouseRef.current, camera);
      const hits = raycasterRef.current.intersectObjects(markersRef.current);
      if (hits.length > 0) {
        setHoveredIsland(hits[0].object.userData);
      } else {
        setHoveredIsland(null);
      }

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    // ── Resize ─────────────────────────────────────────────────────────────
    const onResize = () => {
      if (!container) return;
      camera.aspect = container.clientWidth / container.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(container.clientWidth, container.clientHeight);
    };
    window.addEventListener('resize', onResize);

    // ── Mouse move ─────────────────────────────────────────────────────────
    const onMouseMove = (e) => {
      const rect = container.getBoundingClientRect();
      mouseRef.current.x =  ((e.clientX - rect.left) / rect.width)  * 2 - 1;
      mouseRef.current.y = -((e.clientY - rect.top)  / rect.height) * 2 + 1;
    };
    container.addEventListener('mousemove', onMouseMove);

    return () => {
      cancelAnimationFrame(animFrameId);
      window.removeEventListener('resize', onResize);
      container.removeEventListener('mousemove', onMouseMove);
      container.removeChild(renderer.domElement);
      renderer.dispose();
    };
  }, []); // run only once

  return (
    <div className="earth-map-container">
      <div className="earth-map-wrapper">
        <div ref={containerRef} className="earth-3d-container" />
        {!isLoaded && (
          <div className="loading-indicator">
            <div className="spinner" />
            <p>Loading 3D Earth...</p>
          </div>
        )}
        {hoveredIsland && (
          <div className="island-tooltip">
            <h3>{hoveredIsland.name} Island</h3>
            <p>{hoveredIsland.description}</p>
            <p className="tooltip-population">🐧 {hoveredIsland.population} penguins</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default EarthMap;
